export const TRANSLATIONS = Object.fromEntries(
  Object.entries(entries).map(([source, values]) => [
    source,
    {
      it: values[0],
      es: values[1],
      fr: values[2],
      de: values[3],
      zh: values[4],
    },
  ]),
);

const reverseLookup = new Map();
Object.entries(TRANSLATIONS).forEach(([source, translations]) => {
  reverseLookup.set(source, source);
  Object.values(translations).forEach((value) => {
    reverseLookup.set(value, source);
  });
});

function splitPadding(value) {
  const raw = String(value ?? '');
  const leading = raw.match(/^\s*/)?.[0] || '';
  const trailing = raw.match(/\s*$/)?.[0] || '';
  return {
    leading,
    trailing,
    core: raw.slice(leading.length, raw.length - trailing.length),
  };
}

